Section.HTMLTemplate:
@{
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
}

@functions {

	void RenderITSMKnowledgeBase(List<dynamic> itsmKnowledgeBase)
	{
		if(itsmKnowledgeBase is not null && itsmKnowledgeBase.Count() > 0) {
			foreach(var item in itsmKnowledgeBase){

				<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
					<div class="card-lmtl4 flex-fill-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-article-id="@item.ID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="me-3-lmtl4">
								<i class="@item.IconCssClass text-@item.ColorCssClass ph-2x d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Title</h6>
								@item.CreateDate @item.AccountID
							</div>
						</a>
					</div>
				</div>
			}
		} else {
			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					<div class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="me-3-lmtl4">
							<i class="ph-file-dotted text-grey ph-2x d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@Resx["NoKnowledgeBaseHere_ITSM"]</h6>
						</div>
					</div>
				</div>
			</div>

		}
	}

}

<div class="row mb-2">
	<div class="col-md-12">
		<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 custom-underlineDanger">
			<li class="nav-item-lmtl4">
				<span class="nav-link-lmtl4 active-lmtl4">
					<i class="ph-file me-2-lmtl4"></i> @Resx["Articles_ITSM"] <span class="badge badge-pill bg-primary-lmtl4 ms-2-lmtl4">@itsmKnowledgeBaseCount</span>
				</span>
			</li>
		</ul>
	</div>
</div>

<div class="row">
	@{
		RenderITSMKnowledgeBase(itsmKnowledgeBase.ToList());
	}
</div>
